head.script:
/**
 * 화 면 명 : 근무복신청
 * 메뉴경로 : 공통/총무업무/피복관리/
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/cm/bc/affairs/zz_770_02_02b.jsp
 * 작 성 자 : 정승혜
 * 작 업 일 : 2025-11-11
 * 수정이력  :
 *    - 2025-11-11      정승혜    최초작성
 *    - 2026-01-27      정승혜    기타수정
 * 
 * 메모 :
 * 조회조건 : 
 * 게시차수-201501, 201601 / 신청지사-부산
 * 게시차수-201901 / 신청지사-유통 -> 수량조절가능
 * 게시차수-201701 / 신청지사-부산 -> 전년도복사 가능 / 스즈키복 알럿 /
 * asis 에서 비고 이후에 컬럼이 있는데 show=false 없이 asis 그리드에 없어서 디자인에 안넣음(개인화작동안함) ->넣음 / 엑셀에 다운되는 문제있음, ds_out 에는 있음
 * 999999 부분은 없애기로 협의함
 * 
 */

scwin.sDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.stdYear = scwin.sDate.substring(0,4);

scwin.memJson = $c.data.getMemInfo(); // 세션정보
scwin.userId  = scwin.memJson.userId;
scwin.isStarted = false;

//-----------------------------------------------------------------------------
// 화면로딩시 
//-----------------------------------------------------------------------------
scwin.onpageload = function() {
    // getCodeList
    const codeOptions = [
        { grpCd : "DRS_L", compID : "lc_deptCd" },
    ];
    $c.data.setCommonCode(codeOptions);

    const param= [
        {
            method: "getLuxeComboData",
            param1: "SheathMgntEBC",
            param2: "retrieveSheathPostSeqCd",
            compID: "lc_postSeq"
        },
        {
            method: "getGridComboByUpperCd",
            param1: "DRESS",
            param2: "ITEM",
            param3: false,
            compID: "gr_out:itemNo"
        }
    ];
    $c.data.setGauceUtil(param);
};

scwin.onUdcCompleted = function() {

};

scwin.ondataload = function() { 
    dlt_commonCodeDRS_L.sort("cd", 0);

    scwin.f_DsHeaderSet();
	scwin.f_DsHeaderSet2();
	scwin.f_CondInit();
};

scwin.f_DsHeaderSet = function() {
    // DataSet의 Header 정보 생성(TODO:TOBE 데이터맵으로 셋팅하므로 필요없음)
};

scwin.f_DsHeaderSet2 = function() {
    // DataSet의 Header 정보 생성(TODO:TOBE 데이터맵으로 셋팅하므로 필요없음)
};

//-------------------------------------------------------------------------
// 조회 조건 초기화
//-------------------------------------------------------------------------
scwin.f_CondInit = function() {
    $c.gus.cfInitObjects(tb_search);
};

//-----------------------------------------------------------------------------
// 조회
//-----------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    scwin.isStarted = true;
    dma_cond2.set( "postSeqCond", dma_cond.get("postSeqCond") );
    let ret = await $c.gus.cfValidate([lc_postSeq,lc_deptCd]);   
    if(!ret ) {
        return;
    }
    $c.sbm.execute(sbm_tr_retrieve);
};

//-----------------------------------------------------------------------------
// 기본 셋팅 조회
//-----------------------------------------------------------------------------
scwin.f_StdRetrieve = async function() {
    let ret = await $c.gus.cfValidate([lc_postSeq,lc_deptCd]);   
    if(!ret ) {
        return;
    }
    $c.sbm.execute(sbm_tr_stdRetrieve);
};

//-----------------------------------------------------------------------------
// 아이템 리스트 조회
//-----------------------------------------------------------------------------
// 행추가할때 사용하는 아이템리스트
scwin.f_ItemRetrieve_add = function() {
    $c.sbm.execute(sbm_tr_retrieveItemList_add);
};

scwin.f_ItemRetrieve = function() {
    $c.sbm.execute(sbm_tr_retrieveItemList);
};
//-----------------------------------------------------------------------------
// 팝업 조회
//-----------------------------------------------------------------------------
scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch, row) {
    if(row == null || row == ""){
        row = 0;
    }

    let deptCd = lc_deptCd.getValue();
	let postSeq = lc_postSeq.getValue();

    switch (disGubun)
    {
        case 1: 
            udc_postSeqEmpNo.cfCommonPopUp(scwin.udc_postSeqEmpNo_callBackFunc,
            pCode,pName,pClose,null,"신청자코드, 신청자명","100,200",'3,4,5,6,7,8,9,10',deptCd,
            null,null,null,null,null,"T","신청자코드,신청자코드,신청자명"); 

        break;

        case 2: 
            udc_gr_postSeqEmpNo.cfCommonPopUp(scwin.udc_gr_postSeqEmpNo_callBackFunc,
            pCode,pName,pClose,null,"신청자코드, 신청자명","100,200",'3,4,5,6,7,8,9,10',deptCd,
            null,null,null,null,null,"T","신청자코드,신청자코드,신청자명"); 

        break;
    default:
  	break;        
    }
};

scwin.gr_out_ontextimageclick = function(rowIndex, colId, nowValue) {
    if(colId == "name"){
        scwin.f_openCommonPopUp(2, '', nowValue,'F','T',rowIndex);
    }
};

scwin.udc_postSeqEmpNo_callBackFunc = function(rtnList) {
    if(rtnList != null && rtnList[0] != "N/A" ) {
        ed_empNo.setValue(rtnList[0]);
	    ed_empNm.setValue(rtnList[1]);
    } else {
        //ed_empNo.setValue("999999");
        ed_empNo.setValue("");
        ed_empNm.setValue(ed_empNm.getValue());
    }
};

scwin.udc_gr_postSeqEmpNo_callBackFunc = function(rtnList) {
    let row = gr_out.getFocusedRowIndex();

    if(rtnList != null && rtnList[0] != "N/A" ) {
        ds_out.setCellData(row, "sabun", rtnList[0]);
        ds_out.setCellData(row, "name", rtnList[1]);
        ds_out.setCellData(row, "jikgubCd", rtnList[2]);
        ds_out.setCellData(row, "jikgubNm", rtnList[3]);
        ds_out.setCellData(row, "deptCd", rtnList[4]);
        ds_out.setCellData(row, "deptNm", rtnList[5]);
        ds_out.setCellData(row, "mgntStaffCd", rtnList[8]);
        ds_out.setCellData(row, "checkDeleteYn", rtnList[9]);
    } else {
        //ds_out.setCellData(row, "sabun", "999999");
        ds_out.setCellData(row, "sabun", "");
        ds_out.setCellData(row, "name", ds_out.getCellData(gr_out.getFocusedRowIndex(), "name"));
        ds_out.setCellData(row, "jikgubCd", "");
        ds_out.setCellData(row, "jikgubNm", "");
        ds_out.setCellData(row, "deptCd", lc_deptCd.getValue());
        ds_out.setCellData(row, "deptNm", "");
        ds_out.setCellData(row, "mgntStaffCd", "");
        ds_out.setCellData(row, "checkDeleteYn", "");
    }

    for(let i=0 ; i<=ds_out.getRowCount(); i++){
        if(ds_out.getRowStatus(i) == "C" && i > row && i < row+6 ){
            if(ds_out.getCellData(i,"chk") != "T" && ds_out.getCellData(i,"name") == ""){
                ds_out.setCellData(i,"sabun", ds_out.getCellData(row,"sabun"));
                ds_out.setCellData(i,"name", ds_out.getCellData(row,"name")); 
                ds_out.setCellData(i,"jikgubCd", ds_out.getCellData(row,"jikgubCd"));
                ds_out.setCellData(i,"jikgubNm", ds_out.getCellData(row,"jikgubNm"));
                ds_out.setCellData(i,"deptCd", ds_out.getCellData(row,"deptCd"));
                ds_out.setCellData(i,"deptNm", ds_out.getCellData(row,"deptNm"));
                ds_out.setCellData(i,"mgntStaffCd", ds_out.getCellData(row,"mgntStaffCd"));
                ds_out.setCellData(i,"firstProvideCd", ds_out.getCellData(row,"firstProvideCd"));
                ds_out.setCellData(i,"checkDeleteYn", ds_out.getCellData(row,"checkDeleteYn"));
            }
        }
    }

    let sabun = ds_out.getCellData(row,"sabun");
    //if(sabun!= "999999"){
        scwin.getfirstProvideCd(lc_postSeq.getValue(), sabun);	
    //}

    if(ds_firstProvideCd.getCellData(0,"col1") == '1')
    {
        ds_out.setCellData(i,"firstProvideCd", "1");
    }
    else if(ds_firstProvideCd.getCellData(0,"col1") == '2')
    {
        ds_out.setCellData(i,"firstProvideCd", "2");
    }
    else if(ds_firstProvideCd.getCellData(0,"col1") == '3')
    {
        ds_out.setCellData(i,"firstProvideCd", "3");
    }

};


scwin.udc_gr_postSeqEmpNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ds_out.getCellData(gr_out.getFocusedRowIndex(), "sabun"), ds_out.getCellData(gr_out.getFocusedRowIndex(), "name"),'F','T',gr_out.getFocusedRowIndex());
};

scwin.udc_gr_postSeqEmpNo_onviewchangeNameEvent = function (info) {
    scwin.f_openCommonPopUp(2, ds_out.getCellData(gr_out.getFocusedRowIndex(), "sabun"), ds_out.getCellData(gr_out.getFocusedRowIndex(), "name"),'F','T',gr_out.getFocusedRowIndex());
};

scwin.udc_gr_postSeqEmpNo_onblurCodeEvent = function (e) {
    scwin.f_openCommonPopUp(2, ds_out.getCellData(gr_out.getFocusedRowIndex(), "sabun"), ds_out.getCellData(gr_out.getFocusedRowIndex(), "name"),'F','T',gr_out.getFocusedRowIndex());
};

scwin.udc_postSeqEmpNo_onviewchangeNameEvent = function (info) {
    scwin.f_openCommonPopUp(1, ed_empNo.getValue(), ed_empNm.getValue(),'T','T','');
};

scwin.udc_postSeqEmpNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_empNo.getValue(), ed_empNm.getValue(),'F','T','');
};

scwin.udc_postSeqEmpNo_onblurCodeEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_empNo.getValue(), ed_empNm.getValue(),'T','T','');
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function() {
    // udc
};

//-----------------------------------------------------------------------------
// 저장
//-----------------------------------------------------------------------------
scwin.f_Save = async function() {
    let ret1 = await $c.gus.cfValidate([gr_out]);
    if( !ret1 ) {
        return;
    }
    if( ds_out.getModifiedIndex().length == 0 ) {
        $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    for(let i= 1 ; i <= ds_out.getRowCount(); i++){
		if(ds_out.getCellData(i,"drsSize") == "")
		{
			ds_out.setCellData(i,"checkDeleteYn", "1");
		}		   
	}

    for(let i= ds_out.getRowCount() ; i >= 0; i--){
		if(ds_out.getCellData(i,"checkDeleteYn") == "1")
		{
            ds_out.deleteRow(i);
		}
	}

    for(let i= 1 ; i <= ds_out.getRowCount(); i++){
        if(ds_out.getCellData(i, "firstProvideCdb") == "3")	//최초로 지급받는 사람
        {	
            if(ds_out.getCellData(i,"mgntStaffCd") == "2"){
                ds_out.setCellData(i, "drsQty", 2); //현장직
            }else{
                ds_out.setCellData(i, "drsQty", 1); //관리직
            }
        }
    }
    $c.sbm.execute(sbm_tr_save);
};

//-----------------------------------------------------------------------------
// 행추가.
//-----------------------------------------------------------------------------
scwin.f_DsOutAddRow = function() {
    //let row = ds_out.insertRow();
    dma_cond2.set("postSeqCond",lc_postSeq.getValue() );
    dma_cond2.set("deptCond",lc_deptCd.getValue() );

    //추가할 아이템리스트를 조회한다
    if(lc_deptCd.getValue() != "" && scwin.isStarted == true){
        scwin.f_ItemRetrieve_add();    
    }
};

//-----------------------------------------------------------------------------
// 선택 사이즈 초기화
//-----------------------------------------------------------------------------
scwin.f_resetSelectedSize = function() {
    let nowRow = ds_out.getRowPosition();

    if(nowRow != null){
        ds_out.setCellData(nowRow, "drsSize", "");
        ds_out.setCellData(nowRow, "drsLength", "");
    }
};

//-----------------------------------------------------------------------------
// 사이즈 일괄 초기화
//-----------------------------------------------------------------------------
scwin.f_resetSize = function() {
	for(let i=0 ; i<=ds_out.getRowCount(); i++){
        ds_out.setCellData(i, "drsSize", "");
        ds_out.setCellData(i, "drsSLength", "");
	}
};

//-----------------------------------------------------------------------------
// 전년도 게시차수의 데이터를 생성해 준다
// ex) 201401 차수에 이 버튼 클릭시 201301 차수의 데이터를 201401 차수에 생성해 준다.
//-----------------------------------------------------------------------------
// 전년도복사
scwin.f_createPreviousYearData = async function() {
    let ret = await $c.gus.cfValidate([lc_postSeq,lc_deptCd]);   
    if(!ret ) {
        return;
    }

    let postSeq = lc_postSeq.getValue();
    let acctDeptCd = lc_deptCd.getValue();
    let creMsg = "선택 게시차수 : " + postSeq +"\n"+
        "선택 신청지사 : " + acctDeptCd + "\n" + 
        "선택 게시차수 전년도의 같은 분기 데이터를 복사 합니다.";

    // \n 줄바꿈 되지 않음      
    await $c.win.alert(creMsg);

    await scwin.getPreviousYearData(postSeq, acctDeptCd);
};

//-------------------------------------------------------------------------
// 전표 등록자 조회
//-------------------------------------------------------------------------
// 전년도복사를 위한 데이터
scwin.getPreviousYearData = function(postSeq, acctDeptCd) {
    let post = postSeq.substring( 0,4 ) -1;
    ds_checkPreviousYearData.removeAll();

    // SELECT 절 
	let param1 = 
		  " A.POST_SEQ   as COL1 "
		+ ",A.DEPT_CD    as COL2 "
		+ ",''   		as COL3 "
		+ ",''   		as COL4 "
		+ ",''  		as COL5 "
		+ ",'' 			as COL6 "
		+ ",'' 			as COL7 "
		+ ",'' 			as COL8 "
		+ ",'' 			as COL9 "
		+ ",'' 			as COL10 "
		;

    // 대상테이블 	
	let param2 = 			
		  " TB_ZZ783 A, TB_ZZ002 B, TB_ZZ002 C "
		 + " WHERE 1=1 "
	     + " AND A.POST_SEQ  BETWEEN '" + post +"' || '01' AND '" + post +"' || '12'"
		 + " AND B.GRP_CD = 'DRESS' "  
		 + " AND C.GRP_CD = 'DRS_L' "
    	 + " AND B.UPPER_CD = C.CD "
         + " AND A.DEPT_CD = B.CD "
 		 + " AND C.CD = '" + acctDeptCd + "'"
         + " AND A.ITEM_NO IN ( "
         + " 		         SELECT ITEM_NO "
         + "              	   FROM TB_ZZ782 "
         + "             	   WHERE POST_SEQ = '" + postSeq + "' ) "
		 + " ORDER BY A.POST_SEQ "
		;


    //let condition = "&param1=" + param1 + "&param2=" + param2;

    const strParam = {
              sysCd : "CommonEBC"
            , queryId : "dinymicQueryTest2"
            , param1 : param1
            , param2 : param2
            };

    ds_check_param.setJSON(strParam);            
    $c.sbm.execute(sbm_ds_checkPreviousYearData);

};

//-------------------------------------------------------------------------
// 전표 등록자 조회
//-------------------------------------------------------------------------
scwin.getfirstProvideCd = function(postSeq, sabun) {
    let post1 = postSeq.substring( 0,4 ) -1;
	ds_firstProvideCd.removeAll();

    // SELECT 절 
	let param1 = 
		  " 	CASE "
		+ " 		WHEN EXISTS ( "
		+ " 						SELECT * "
		+ " 						  FROM TB_ZZ783 K "
		+ " 						 WHERE A.EMP_NO = K.SABUN "
		+ " 						   AND K.POST_SEQ  BETWEEN '" + post1 +"' || '01' AND '" + post1 +"' || '12'"
		+ " 						   AND K.ITEM_NO IN ( "
		+ " 											SELECT ITEM_NO "
		+ " 											  FROM TB_ZZ782 "
		+ " 											 WHERE POST_SEQ = '" + postSeq + "' )) THEN '1' "
		+ " 		WHEN A.MCOM_ENT_DT <= TO_CHAR(ADD_MONTHS(SYSDATE, -12), 'YYYYMMDD') THEN '2' "
		+ " 	ELSE '3' "
		+ " END AS COL1 "
		+ ",''    		as COL2 "
		+ ",''   		as COL3 "
		+ ",''   		as COL4 "
		+ ",''  		as COL5 "
		+ ",'' 			as COL6 "
		+ ",'' 			as COL7 "
		+ ",'' 			as COL8 "
		+ ",'' 			as COL9 "
		+ ",'' 			as COL10 "
		;

	// 대상테이블 	
	let param2 = 			
		  " TB_ZZ310 A "
		;

	// 조건절	  
	let param3 = 						  
		   " AND A.EMP_NO = '" + sabun + "'  "
	    ;

	// 정렬    
	let param4 = 	
		  " COL1 "
		;

    let condition = "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=" + param4;

    const strParam = {
              sysCd : "CommonEBC"
            , queryId : "dinymicQueryTest"
            , param1 : param1
            , param2 : param2
            , param3 : param3
            , param4 : param4
            };

    ds_check_first_param.setJSON(strParam);            
    $c.sbm.execute(sbm_ds_firstProvideCd);
};

//-----------------------------------------------------------------------------
//  사이즈 조회.
//-----------------------------------------------------------------------------
scwin.f_SizeDsSet = function(grpCd) {
    let condition = "?grpCd=" + grpCd;
    sbm_ds_size.action = "/cm.zz.RetrieveCodeCMD.do" + condition; 
    $c.sbm.execute(sbm_ds_size);
};

//-----------------------------------------------------------------------------
//  선택일괄삭제
//-----------------------------------------------------------------------------
scwin.f_DeleteRow = function() {
    let chkCnt = 0;
	let chk = "";

	for(let j=0; j <= ds_out.getRowCount(); j++){
        let sts = ds_out.getRowStatus(j);
		chk = ds_out.getCellData(j, "chk")

		if (chk == "T"){
            if(sts == "C") {
                ds_out.removeRow(j);
            }else if(sts == "D"){
                //아무동작 하지 않음
            }else{
                ds_out.deleteRow(j);
            }
            //gr_out.setRowDisabled(j, true);
			chkCnt++;
		}
	}
	if(chkCnt == 0){
        $c.win.alert("체크된 내역이 없습니다.");
	}
};

//-----------------------------------------------------------------------------
//  기본셋팅일 경우 데이터셋 상태값 입력으로 변경
//-----------------------------------------------------------------------------
scwin.f_chgGauceSts = function() {
    for(let i=0; i <= ds_out.getRowCount(); i++){
        ds_out.modifyRowStatus(i, "C");
        ds_out.setCellData(i, "chk", "T");
	}
};

//-------------------------------------------------------------------------
//      checkBox
//------------------------------------------------------------------------- 
scwin.f_chkAll = function() {
    // OnHeadCheckClick(Col,Colid,bCheck)
};

// 행추가 행위
scwin.f_DsOutAddFn = function() {
    let row = 0;
    for(let i= 0 ; i <= ds_itemList.getRowCount()-1; i++){
        let nowRow = ds_out.insertRow();
        row = nowRow;
        ds_out.setCellData(row, "postSeq", lc_postSeq.getValue() );
        ds_out.setCellData(row, "itemNo", ds_itemList.getCellData(i, "itemNo") );
        ds_out.setCellData(row, "dressType", ds_itemList.getCellData(i, "dressType") );
        ds_out.setCellData(row, "topnbotDiv", ds_itemList.getCellData(i, "topnbotDiv") );
        ds_out.setCellData(row, "seasonDiv", ds_itemList.getCellData(i, "seasonDiv") );
        ds_out.setCellData(row, "unitPrice", ds_itemList.getCellData(i, "unitPrice") );
        ds_out.setCellData(row, "drsQty", 1 );
    }
    $c.gus.cfGoPrevPosition(gr_out, row);
};

// 행삭제
scwin.f_DsOutDelRow = function() {
    let nowRow = ds_out.getRowPosition();
    let sts = ds_out.getRowStatus(gr_out.getFocusedRowIndex());
    if(nowRow != null){
        if(sts == "C") {
            ds_out.removeRow(nowRow);
            $c.gus.cfGoPrevPosition(gr_out, nowRow-1);
        }else if(sts == "D"){
            //아무동작 하지 않음
        }else{
            ds_out.deleteRow(nowRow);
            //gr_out.setRowDisabled(nowRow, true);
        }
    }
};

// grid decode format
scwin.mgntStaffCdDisplayFm = function(data) {
    return $c.gus.decode(data, 1, "관리직", 2, "현장직");
}

// 셀클릭했을때 사이즈,기장 데이터리스트
// as is OnDropDown / OnClick(Row,Colid)
scwin.gr_out_oncellclick = function (rowIndex, columnIndex, columnId) {
	if(lc_deptCd.getValue() != "D204"){
        gr_out.setCellReadOnly(rowIndex, "drsLength", true);
	} else{
        gr_out.setCellReadOnly(rowIndex, "drsLength", false);
	}

 	let topnbotDiv = ds_out.getCellData(rowIndex, "topnbotDiv");
 	let dressType = ds_out.getCellData(rowIndex, "dressType");

    //신청지사-유통E840 -> 수량조절가능(dbclick)
    if(lc_deptCd.getValue() == "E840"){
        gr_out.setCellReadOnly(rowIndex, "drsQty", false);
    }else{
        gr_out.setCellReadOnly(rowIndex, "drsQty", true);
    }

    // 기장 클릭했을때
    if(columnId == "drsLength"){
		if(topnbotDiv == 'B'){ 
			scwin.f_SizeDsSet("DRS_Z");
		}else{ 
			scwin.f_SizeDsSet("DRS_N");
		}
	}

    // 사이즈 클릭했을때
    if(columnId == "drsSize"){
        let info = {
            inputType : "select" ,
             options : {
                selectedData : false,
                viewType: "icon",
                chooseOption: true,
                chooseOptionLabel: "$blank",
                chooseOptionValue: "$blank"
            }, 
            itemSet : {
                nodeset: "data:ds_size", 
                label: "cdNm",
                value: "cd"
            } 
        }

		if(dressType == "EG" || dressType == "EN"){
			scwin.f_SizeDsSet("DRS_O");
		}else{
			if(topnbotDiv == 'T'){              // 상의
				scwin.f_SizeDsSet("DRS_T");
			}else if(topnbotDiv == 'B'){        // 하의
				scwin.f_SizeDsSet("DRS_B");
			}else if(topnbotDiv == 'A'){        // 스즈키복
				scwin.f_SizeDsSet("DRS_N");
			}
		}

        gr_out.setFocusedCell(rowIndex, "drsSize", false);
        $p.setTimeout(function() {
            gr_out.setCellInputType(rowIndex, "drsSize", info);
            gr_out.setFocusedCell(rowIndex, "drsSize", true);
        }, {"delay":50});

	}
};

// 기본 셋팅 조회 서브미션
scwin.sbm_tr_stdRetrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    totalRows.setValue(ds_out.getRowCount());

    scwin.f_ItemRetrieve();	
    $c.util.setTimeout(function() {
        scwin.f_chgGauceSts();
    }, {"delay":200});  

    let now = scwin.sDate;
    let nowYear = scwin.stdYear; 

    for(let i=0; i <= ds_out.getRowCount(); i++){

        let sabun = ds_out.getCellData(i, "sabun");
        let itemNo = ds_out.getCellData(i, "itemNo");

        //신입사원 체크
        if(sabun.substring(0,2) == nowYear.substring(2,4) && (itemNo.substring(0,2) =="EN" || 
        itemNo.substring(0,2) =="EB" || itemNo.substring(0,2) =="EU" || itemNo.substring(0,2) =="RA" || 
        itemNo.substring(0,2) =="SU" || itemNo.substring(0,2) =="SZ" ) ){
            ds_out.setCellData(i, "drsQty", "2");
        }
    }

};

