// 전년도복사를 위한 데이터 서브미션
scwin.sbm_ds_checkPreviousYearData_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    let previousYearData = "";
    let count = 0;

    for(let i=0; i<= ds_checkPreviousYearData.getRowCount(); i++){
        previousYearData = ds_checkPreviousYearData.getCellData(i, "col1");

        if(previousYearData != ''){
            count++;
        }
    }

    if(count == "0"){
        $c.win.alert("선택 게시차수 전년도의 같은 분기 데이터가 존재하지 않습니다.");
        return;
    }

    if(count > 0){
        dma_cond3.set( "postSeqCond" , dma_cond.get("postSeqCond") );
        dma_cond3.set( "deptCond" , dma_cond.get("deptCond") );
        $c.sbm.execute(sbm_tr_save2);
    } 
};

scwin.gr_out_oneditend = async function (row, columnIndex, value) {
    let colId = gr_out.getColumnID(columnIndex);

    let userNm1 = "";
    userNm1 = ds_out.getCellData(row, "name");
    let itemNo = ds_out.getCellData(row, "itemNo");

    if(colId == "name"){
        scwin.f_openCommonPopUp(2, '', value,'T','T',row);
    }

	if(colId == "itemNo"){
        itemNo = ds_out.getCellData(row, "itemNo");
        ds_out.setCellData(row, "dressType", itemNo.substring(0,2) );
        ds_out.setCellData(row, "topnbotDiv", itemNo.substring(3,4) );
        ds_out.setCellData(row, "seasonDiv", itemNo.substring(5,6) );
	}
    let userNm2 = "";
    if(colId == "drsSize"){
		for(let i=0 ; i<=ds_out.getRowCount(); i++){			
			userNm2 = ds_out.getCellData(i, "name");
				if(userNm1 == userNm2) {// start of if

					// 하복 
					if(ds_out.getCellData(ds_out.getRowPosition(), "itemNo") == 'SZ-A-S')	
                    // 스즈키복-하복 클릭시
					{
						if( (    ds_out.getCellData(i, "itemNo") == 'SU-B-S' && ds_out.getCellData(i, "drsSize") != ''   ) ||
							(   ds_out.getCellData(i, "itemNo") == 'SU-T-S' && ds_out.getCellData(i, "drsSize") != ''   ) )
						{
                            await $c.win.alert("'현장복-상의-하복' 또는 '현장복-하의-하복' 을 신청하는 경우\n'스즈키복-하복' 을 신청할 수 없습니다.");
                            ds_out.setCellData(ds_out.getRowPosition(), "drsSize", "");
							return;
						}
					}

					// 현장복-하의-하복
                    if(ds_out.getCellData(ds_out.getRowPosition(), "itemNo") == 'SU-B-S')	
					{
						if(     ds_out.getCellData(i, "itemNo") == 'SZ-A-S' && ds_out.getCellData(i, "drsSize") != ''   )   
						{
							await $c.win.alert("'스즈키복-하복' 을 신청하는 경우\n'현장복-상의-하복' 또는 '현장복-하의-하복' 을 신청할 수 없습니다.");
                            ds_out.setCellData(ds_out.getRowPosition(), "drsSize", "");
							return;
						}
					}

                    // 현장복-상의-하복
                    if(ds_out.getCellData(ds_out.getRowPosition(), "itemNo") == 'SU-T-S')	
					{
						if(    ds_out.getCellData(i, "itemNo") == 'SZ-A-S' && ds_out.getCellData(i, "drsSize") != '' )

						{
							await $c.win.alert("'스즈키복-하복' 을 신청하는 경우\n'현장복-상의-하복' 또는 '현장복-하의-하복' 을 신청할 수 없습니다.");
                            ds_out.setCellData(ds_out.getRowPosition(), "drsSize", "");
							return;
						}
					}

					//동복
					if(ds_out.getCellData(ds_out.getRowPosition(), "itemNo") == 'SZ-A-W')	
                    // 스즈키복-동복
					{
						if( (    ds_out.getCellData(i, "itemNo") == 'SU-B-W' && ds_out.getCellData(i, "drsSize") != '' ) ||
							(   ds_out.getCellData(i, "itemNo") == 'SU-T-W' && ds_out.getCellData(i, "drsSize") != '' )  )
						{
							await $c.win.alert("'현장복-상의-동복' 또는 '현장복-하의-동복' 을 신청하는 경우\n'스즈키복-동복' 을 신청할 수 없습니다.");
							ds_out.setCellData(ds_out.getRowPosition(), "drsSize", "");
							return;
						}
					}

					if(ds_out.getCellData(ds_out.getRowPosition(), "itemNo") == 'SU-B-W')	// 현장복-하의-동복
					{
						if(    ds_out.getCellData(i, "itemNo") == 'SZ-A-W' && ds_out.getCellData(i, "drsSize") != '' )
						{
							await $c.win.alert("'스즈키복-동복' 을 신청하는 경우\n'현장복-상의-동복' 또는 '현장복-하의-동복' 을 신청할 수 없습니다.");
							ds_out.setCellData(ds_out.getRowPosition(), "drsSize", "");
							return;
						}
					}

					if(ds_out.getCellData(ds_out.getRowPosition(), "itemNo") == 'SU-T-W')	// 현장복-상의-동복
					{
						if(    ds_out.getCellData(i, "itemNo") == 'SZ-A-W' && ds_out.getCellData(i, "drsSize") != '' )
						{
							await $c.win.alert("'스즈키복-동복' 을 신청하는 경우\n'현장복-상의-동복' 또는 '현장복-하의-동복' 을 신청할 수 없습니다.");
                            ds_out.setCellData(ds_out.getRowPosition(), "drsSize", "");
							return;
						}
					}

				} // end of if
		} // end of for
	}
};

